    func discoverPrinters(fResult: @escaping FlutterResult ) {
    stopDiscovery()

    printerList.removeAll()

        self.filterOption.portType = EPOS2_PORTTYPE_BLUETOOTH.rawValue

    let status = Epos2Discovery.start(self.filterOption, delegate: self)
    if (status != EPOS2_SUCCESS.rawValue) {
      printDebugLog("🛑 did fail to start discovery process")
      fResult(PrinterError.startDiscovery.rawValue + "Did fail to start discovery")
    } else {
      printDebugLog("🟢 did start discovery process")

      // Gather all the results after `timeout` and return the response
      let deadline = dispatchTime(fromMilliseconds: Int(timeout))
      DispatchQueue.global(qos: .userInitiated).asyncAfter(deadline: deadline, execute: { [weak self] in
        // Collect all the values received
        let discoveredDevices = self?.printerList ?? []


          fResult(discoveredDevices)
      })
    }
  }
    func getDevices(result: @escaping FlutterResult){
        result(printerList)
    }

  func setupPrinter(target: String, series: Int, lang: Int) {
    if let printer = printer {
      printer.clearCommandBuffer()
      printer.setReceiveEventDelegate(nil)
    }
    self.printer = nil
    self.isConnected = false

    printer = Epos2Printer(printerSeries: Int32(series), lang: Int32(lang))
    self.target = target
    printer?.setReceiveEventDelegate(self)


  }

    func pairingBluetoothPrinter(target:Any,fResult: @escaping FlutterResult) {

    guard let pairingPrinter = pairingPrinter else {
        fResult(PrinterError.startBluetooth.rawValue + "did fail to start bluetooth connection")
      return
    }

        let result = pairingPrinter.connectDevice(target as? NSMutableString )
    switch (result) {
    case EPOS2_BT_SUCCESS.rawValue + EPOS2_BT_ERR_ALREADY_CONNECT.rawValue:
        fResult(EPOS2_BT_SUCCESS.rawValue)
        self.target= target
      break
    default:
      self.printer?.disconnect()
        pairingPrinter.disconnectDevice(target as? String)
        fResult(bluetoothMessage(code: result))
      break
    }
  }

  func addCut(fResult: @escaping FlutterResult) {
    guard let printer = printer else {
        fResult(PrinterError.notFound.rawValue + "did fail to cut paper: no printer")
      return
    }
    let result = printer.addCut(EPOS2_CUT_FEED.rawValue)
    if (result != EPOS2_SUCCESS.rawValue) {
        fResult(PrinterError.cmdAddCut.rawValue + "did fail to cut paper: no printer")
    }
      fResult(true)
