func connectAndPrintSample(target: String) {
    let printer = Epos2Printer(printerSeries: EPOS2_TM_T88.rawValue, lang: EPOS2_MODEL_ANK.rawValue)

    let resultConnect = printer?.connect(target, timeout: Int(EPOS2_PARAM_DEFAULT))
    if resultConnect != EPOS2_SUCCESS.rawValue {
        print("Connection failed with error: \(String(describing: resultConnect))")
        return
    }

    let resultBeginTransaction = printer?.beginTransaction()
    if resultBeginTransaction != EPOS2_SUCCESS.rawValue {
        print("Begin transaction failed with error: \(String(describing: resultBeginTransaction))")
        printer?.disconnect()
        return
    }

    // Add text to print
    _ = printer?.addText("Hello, Epson Printer!\n")

    // Trigger the actual print
    let resultPrint = printer?.sendData(Int(EPOS2_PARAM_DEFAULT))
    if resultPrint != EPOS2_SUCCESS.rawValue {
        print("Print failed with error: \(String(describing: resultPrint))")
    }

    printer?.endTransaction()
    printer?.disconnect()
    printer?.clearCommandBuffer()

    // Always release the object when done
    self.printer = nil
}
```

